#include <WiFi.h>
#include <HTTPClient.h>

void setup() {
  WiFi.begin("Wokwi-GUEST", "");
  while (WiFi.status() != WL_CONNECTED) { delay(100); }
}

void loop() {
  HTTPClient http;
  http.begin("http://host.docker.internal:3000/data");
  http.addHeader("Content-Type", "application/json");
  String json = "{\"eau\":120,\"electricite\":450}";
  http.POST(json);
  http.end();
  delay(5000);
}
